function out = fSpotAnalysisV01(x,y,img)%% Perform spot analysis, peak and mean location,% FWHM for lineout through peak,% std for integrated array.%% out = fSpotAnalysisV01(x,y,img_in)%% x,y: axis information (x axis)% img: image% img: source image%% out: output array%       1-2: peak location (x,y)%       3-4: mean location (x,y)%       5-6: FWHM (x,y, from inside)%       7-8: std (standard deviation, x,y)%%% Function spot analysis, ver.1%% Kei Nakamura% Created on Friday, Octover 28th 2011.% Modified on %% 2011/10/28 ver.1: created% 2013/11/5 ver.1b: clean up%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body% get peak location[~,rows] = max(img);[~,maxXi] = max(max(img)); % max x indexmaxYi = rows(maxXi);            % max y index% get fwhm (lineout along peak)[fwhmX,~,~,~,peakXi] = fGetFwhmV04(x,img(maxYi,:));peakX = x(peakXi);%fwhmX = hwhmHIn+hwhmLIn;    % fwhm for x from lineout[fwhmY,~,~,~,peakYi] = fGetFwhmV04(y,img(:,maxXi));peakY = y(peakYi);%fwhmY = hwhmHIn+hwhmLIn;    % fwhm for y from lineout% get rms (sum)[stdX,meanX] = fGetRmsV01(x,sum(img));[stdY,meanY] = fGetRmsV01(y,sum(img,2)');out(1:2) = [peakX,peakY]; % peak locationout(3:4) = [meanX,meanY]; % peak locationout(5:6) = [fwhmX,fwhmY]; % peak locationout(7:8) = [stdX,stdY]; % peak location
